import{_ as e,c as a,o as s,a2 as o}from"./chunks/framework.DdOM6S6U.js";const b=JSON.parse('{"title":"Module System","description":"","frontmatter":{"sidebarPos":8,"sidebarTitle":"Modules"},"headers":[],"relativePath":"system-reference/modules.md","filePath":"system-reference/modules.md","lastUpdated":null}'),t={name:"system-reference/modules.md"},n=o(`<h1 id="module-system" tabindex="-1">Module System <a class="header-anchor" href="#module-system" aria-label="Permalink to &quot;Module System&quot;">​</a></h1><h2 id="module-vs-route-activation" tabindex="-1">Module vs Route Activation <a class="header-anchor" href="#module-vs-route-activation" aria-label="Permalink to &quot;Module vs Route Activation&quot;">​</a></h2><p>Modularity has two activation concepts:</p><ol><li><p><strong>Module enable/disable</strong>: Via Nwidart&#39;s activator (e.g. <code>modules_statuses.json</code> or database). Controls whether a module is loaded at all.</p></li><li><p><strong>Route enable/disable</strong>: Via <code>ModuleActivator</code> and per-module <code>routes_statuses.json</code>. Controls which routes within an enabled module are registered.</p></li></ol><p>A module can be enabled but have specific routes disabled (e.g. hide the create route).</p><h2 id="module-discovery" tabindex="-1">Module Discovery <a class="header-anchor" href="#module-discovery" aria-label="Permalink to &quot;Module Discovery&quot;">​</a></h2><p>Modules are scanned from:</p><ul><li><code>config(&#39;modules.paths.modules&#39;)</code> (default: <code>modules/</code>)</li><li><code>config(&#39;modules.scan.paths&#39;)</code> when scan is enabled</li></ul><p>Each module directory must contain <code>module.json</code>.</p><h2 id="module-provider-registration" tabindex="-1">Module Provider Registration <a class="header-anchor" href="#module-provider-registration" aria-label="Permalink to &quot;Module Provider Registration&quot;">​</a></h2><p><strong>Convention</strong>: <code>ModuleServiceProvider</code> loads <code>*ServiceProvider.php</code> from each module&#39;s <code>Providers/</code> folder. No need to list providers in <code>module.json</code>.</p><p><strong>Optional</strong>: The <code>providers</code> array in <code>module.json</code> can list additional provider classes for explicit registration.</p><h2 id="module-structure" tabindex="-1">Module Structure <a class="header-anchor" href="#module-structure" aria-label="Permalink to &quot;Module Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>modules/MyModule/</span></span>
<span class="line"><span>├── module.json</span></span>
<span class="line"><span>├── Config/</span></span>
<span class="line"><span>├── Database/Migrations/</span></span>
<span class="line"><span>├── Entities/</span></span>
<span class="line"><span>├── Http/Controllers/</span></span>
<span class="line"><span>├── Providers/          # *ServiceProvider.php auto-loaded</span></span>
<span class="line"><span>├── Repositories/</span></span>
<span class="line"><span>├── Routes/</span></span>
<span class="line"><span>│   ├── web.php</span></span>
<span class="line"><span>│   ├── front.php</span></span>
<span class="line"><span>│   ├── api.php</span></span>
<span class="line"><span>└── Resources/</span></span>
<span class="line"><span>    ├── lang/</span></span>
<span class="line"><span>    └── views/</span></span></code></pre></div><h2 id="route-actions" tabindex="-1">Route Actions <a class="header-anchor" href="#route-actions" aria-label="Permalink to &quot;Route Actions&quot;">​</a></h2><p>Standard route actions (Module::$routeActionLists): restore, forceDelete, duplicate, index, create, store, show, edit, update, destroy, bulkDelete, bulkForceDelete, bulkRestore, tags, tagsUpdate, assignments, createAssignment</p><h2 id="route-status" tabindex="-1">Route Status <a class="header-anchor" href="#route-status" aria-label="Permalink to &quot;Route Status&quot;">​</a></h2><p>Use <code>php artisan modularity:route:enable</code> and <code>modularity:route:disable</code> to toggle routes. Status is stored in <code>modules/{ModuleName}/routes_statuses.json</code>.</p><p>See <a href="/guide/commands/route-enable">route:enable</a> and <a href="/guide/commands/route-disable">route:disable</a>.</p>`,19),d=[n];function l(r,i,c,u,p,h){return s(),a("div",null,d)}const v=e(t,[["render",l]]);export{b as __pageData,v as default};
